def solve_maze(maze):
    N = len(maze)

    sol = [[0 for _ in range(N)] for _ in range(N)]

    if maze[0][0] == 0:
        return [[0 for _ in range(N)] for _ in range(N)]

    def is_safe(r, c):
        return 0 <= r < N and \
               0 <= c < N and \
               maze[r][c] == 1 and \
               sol[r][c] == 0

    def solve_maze_util(r, c):
        if r == N - 1 and c == N - 1:
            sol[r][c] = 1
            return True

        sol[r][c] = 1

        dr = [-1, 1, 0, 0]
        dc = [0, 0, -1, 1]

        for i in range(4):
            next_r, next_c = r + dr[i], c + dc[i]

            if is_safe(next_r, next_c):
                if solve_maze_util(next_r, next_c):
                    return True

        sol[r][c] = 0
        return False

    if solve_maze_util(0, 0):
        return sol
    else:
        return [[0 for _ in range(N)] for _ in range(N)]
